1	// Smoke test for the deployed apply-to-listing edge function (US-041).
2	//
3	// Usage: bun run scripts/test/apply-to-listing.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY always. MARKETIFY_JWT_SECRET
5	// unlocks JWT-authed tests; SUPABASE_SERVICE_ROLE_KEY unlocks the
6	// insert/cleanup + ineligibility + already-applied cases. Missing either
7	// secret SKIPs the corresponding assertions with a printed notice rather
8	// than failing.
9	//
10	// Asserts:
11	//   1. Missing Authorization → 401 UNAUTHORIZED                               [always]
12	//   2. Non-Bearer token → 401 UNAUTHORIZED                                    [always]
13	//   3. JWT signed with wrong secret → 401 UNAUTHORIZED                        [always]
14	//   4. Lister-role JWT → 403 FORBIDDEN                                        [jwtSecret]
15	//   5. Malformed JSON body → 400 INVALID_JSON                                 [jwtSecret]
16	//   6. Missing listing_id → 400 INVALID_REQUEST                               [jwtSecret]
17	//   7. Non-UUID listing_id → 400 INVALID_REQUEST                              [jwtSecret]
18	//   8. Non-string cover_note → 400 INVALID_REQUEST                            [jwtSecret]
19	//   9. Over-long cover_note → 400 INVALID_REQUEST                             [jwtSecret]
20	//  10. Unknown listing_id → 404 LISTING_NOT_FOUND                             [jwtSecret]
21	//  11. Ineligible listing (forced tiktok_follower_count=500, threshold 1000)
22	//      → 403 INELIGIBLE with failed_conditions containing tiktok
23	//        min_followers required=1000 actual=500                               [jwtSecret + serviceRole]
24	//  12. Happy path — seed creator applies to seed listing with a cover_note →
25	//      200 with { application_id, listing_version_id }                        [jwtSecret + serviceRole]
26	//  13. Second apply to the same listing by the same creator
27	//      → 409 ALREADY_APPLIED                                                  [jwtSecret + serviceRole]
28	//
29	// The happy-path test cleans up the inserted application row at the end
30	// (idempotency across re-runs). Test row pattern:
31	//   applications.listing_id      = SEED_LISTING_ID
32	//   applications.creator_id      = SEED_CREATOR_USER_ID
33	//   applications.cover_note LIKE 'US-041 smoke test%'
34	// All rows matching that cover_note pattern are deleted in the `finally`
35	// block so a failed mid-run doesn't poison subsequent runs.
36	
37	const supabaseUrl = process.env.SUPABASE_URL;
38	const anonKey = process.env.SUPABASE_ANON_KEY;
39	const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
40	const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
41	if (!supabaseUrl || !anonKey) {
42	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
43	  process.exit(1);
44	}
45	if (!jwtSecret) {
46	  console.log(
47	    "MARKETIFY_JWT_SECRET missing — skipping assertions 4–13",
48	  );
49	}
50	if (!serviceRoleKey) {
51	  console.log(
52	    "SUPABASE_SERVICE_ROLE_KEY missing — skipping assertions 11–13",
53	  );
54	}
55	
56	const endpoint = `${supabaseUrl}/functions/v1/apply-to-listing`;
57	
58	// Seed fixtures — same UUIDs used by get-listing-detail smoke test.
59	const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
60	const SEED_LISTING_ID = "11111111-1111-1111-1111-111111111010";
61	
62	const encoder = new TextEncoder();
63	
64	function b64url(bytes: Uint8Array): string {
65	  let s = "";
66	  for (const b of bytes) s += String.fromCharCode(b);
67	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
68	}
69	
70	async function signMarketifyJwt(
71	  claims: { sub: string; role: "creator" | "lister"; session_id: string },
72	  secret: string,
73	): Promise<string> {
74	  const now = Math.floor(Date.now() / 1000);
75	  const payload = { ...claims, iat: now, exp: now + 300 };
76	  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
77	  const body = b64url(encoder.encode(JSON.stringify(payload)));
78	  const signingInput = `${header}.${body}`;
79	  const key = await crypto.subtle.importKey(
80	    "raw",
81	    encoder.encode(secret),
82	    { name: "HMAC", hash: "SHA-256" },
83	    false,
84	    ["sign"],
85	  );
86	  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
87	  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
88	}
89	
90	async function post(
91	  bodyValue: string | Record<string, unknown> | null,
92	  authHeader: string | null,
93	) {
94	  const headers: Record<string, string> = {
95	    "Content-Type": "application/json",
96	    apikey: anonKey!,
97	  };
98	  if (authHeader) headers["Authorization"] = authHeader;
99	  const res = await fetch(endpoint, {
100	    method: "POST",
101	    headers,
102	    body: bodyValue == null
103	      ? undefined
104	      : typeof bodyValue === "string"
105	      ? bodyValue
106	      : JSON.stringify(bodyValue),
107	  });
108	  const data = await res.json().catch(() => null);
109	  return { status: res.status, data };
110	}
111	
112	function expect(label: string, cond: boolean, ctx: unknown) {
113	  if (!cond) {
114	    console.error(`FAIL ${label}:`, JSON.stringify(ctx, null, 2));
115	    process.exit(1);
116	  }
117	  console.log(`ok — ${label}`);
118	}
119	
120	async function setCreatorMetric(
121	  column: "tiktok_follower_count",
122	  value: number | null,
123	): Promise<void> {
124	  const res = await fetch(
125	    `${supabaseUrl}/rest/v1/creator_profiles?user_id=eq.${SEED_CREATOR_USER_ID}`,
126	    {
127	      method: "PATCH",
128	      headers: {
129	        apikey: serviceRoleKey!,
130	        Authorization: `Bearer ${serviceRoleKey}`,
131	        "Content-Type": "application/json",
132	        Prefer: "return=minimal",
133	      },
134	      body: JSON.stringify({ [column]: value }),
135	    },
136	  );
137	  if (!res.ok) {
138	    throw new Error(`setCreatorMetric failed: ${res.status} ${await res.text()}`);
139	  }
140	}
141	
142	async function deleteSmokeApplications(): Promise<void> {
143	  if (!serviceRoleKey) return;
144	  // Using the cover_note LIKE filter + creator/listing scoping means we
145	  // never touch real application rows even if someone pointed the test at
146	  // prod by mistake.
147	  const url = `${supabaseUrl}/rest/v1/applications` +
148	    `?listing_id=eq.${SEED_LISTING_ID}` +
149	    `&creator_id=eq.${SEED_CREATOR_USER_ID}` +
150	    `&cover_note=like.US-041 smoke test*`;
151	  const res = await fetch(url, {
152	    method: "DELETE",
153	    headers: {
154	      apikey: serviceRoleKey,
155	      Authorization: `Bearer ${serviceRoleKey}`,
156	      Prefer: "return=minimal",
157	    },
158	  });
159	  if (!res.ok) {
160	    console.warn(`cleanup delete failed: ${res.status} ${await res.text()}`);
161	  }
162	}
163	
164	// Snapshot the seed creator's tiktok_follower_count so we can restore it
165	// after the ineligibility case. Only fetched when we have service role.
166	let originalTiktokFollowerCount: number | null = null;
167	if (serviceRoleKey) {
168	  const snapRes = await fetch(
169	    `${supabaseUrl}/rest/v1/creator_profiles?user_id=eq.${SEED_CREATOR_USER_ID}&select=tiktok_follower_count`,
170	    {
171	      headers: {
172	        apikey: serviceRoleKey,
173	        Authorization: `Bearer ${serviceRoleKey}`,
174	      },
175	    },
176	  );
177	  if (!snapRes.ok) {
178	    console.error("creator_profiles snapshot failed:", await snapRes.text());
179	    process.exit(1);
180	  }
181	  const rows = (await snapRes.json()) as Array<{ tiktok_follower_count: number | null }>;
182	  if (rows.length === 0) {
183	    console.error(
184	      "seed creator_profiles missing — run seed fixtures before this test",
185	    );
186	    process.exit(1);
187	  }
188	  originalTiktokFollowerCount = rows[0].tiktok_follower_count;
189	}
190	
191	let restored = false;
192	async function restore() {
193	  if (restored) return;
194	  restored = true;
195	  if (serviceRoleKey) {
196	    await setCreatorMetric("tiktok_follower_count", originalTiktokFollowerCount);
197	  }
198	  await deleteSmokeApplications();
199	}
200	
201	// Ensure a clean slate before each run — a leftover application from a
202	// prior failed run would blow up the happy-path assertion with a
203	// premature 409 ALREADY_APPLIED.
204	await deleteSmokeApplications();
205	
206	try {
207	  // 1. No Authorization header
208	  {
209	    const r = await post({ listing_id: SEED_LISTING_ID }, null);
210	    expect(
211	      "missing auth → 401 UNAUTHORIZED",
212	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
213	      r,
214	    );
215	  }
216	
217	  // 2. Non-Bearer scheme
218	  {
219	    const r = await post({ listing_id: SEED_LISTING_ID }, "Basic abcdef");
220	    expect(
221	      "non-bearer → 401 UNAUTHORIZED",
222	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
223	      r,
224	    );
225	  }
226	
227	  // 3. JWT signed with wrong secret
228	  {
229	    const badJwt = await signMarketifyJwt(
230	      {
231	        sub: SEED_CREATOR_USER_ID,
232	        role: "creator",
233	        session_id: crypto.randomUUID(),
234	      },
235	      "wrong-secret-" + Math.random().toString(36).slice(2),
236	    );
237	    const r = await post({ listing_id: SEED_LISTING_ID }, `Bearer ${badJwt}`);
238	    expect(
239	      "wrong-secret JWT → 401 UNAUTHORIZED",
240	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
241	      r,
242	    );
243	  }
244	
245	  if (jwtSecret) {
246	    // 4. Lister-role JWT (valid signature, wrong role)
247	    {
248	      const listerJwt = await signMarketifyJwt(
249	        {
250	          sub: crypto.randomUUID(),
251	          role: "lister",
252	          session_id: crypto.randomUUID(),
253	        },
254	        jwtSecret,
255	      );
256	      const r = await post(
257	        { listing_id: SEED_LISTING_ID },
258	        `Bearer ${listerJwt}`,
259	      );
260	      expect(
261	        "lister-role JWT → 403 FORBIDDEN",
262	        r.status === 403 && r.data?.error === "FORBIDDEN",
263	        r,
264	      );
265	    }
266	
267	    const creatorJwt = await signMarketifyJwt(
268	      {
269	        sub: SEED_CREATOR_USER_ID,
270	        role: "creator",
271	        session_id: crypto.randomUUID(),
272	      },
273	      jwtSecret,
274	    );
275	    const creatorAuth = `Bearer ${creatorJwt}`;
276	
277	    // 5. Malformed JSON body
278	    {
279	      const r = await post("{not-json", creatorAuth);
280	      expect(
281	        "malformed JSON → 400 INVALID_JSON",
282	        r.status === 400 && r.data?.error === "INVALID_JSON",
283	        r,
284	      );
285	    }
286	
287	    // 6. Missing listing_id
288	    {
289	      const r = await post({}, creatorAuth);
