1	// Smoke test for the deployed apply-to-listing edge function (US-041).
2	//
3	// Usage: bun run scripts/test/apply-to-listing.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY always. MARKETIFY_JWT_SECRET
5	// unlocks JWT-authed tests; SUPABASE_SERVICE_ROLE_KEY unlocks the
6	// insert/cleanup + ineligibility + already-applied cases. Missing either
7	// secret SKIPs the corresponding assertions with a printed notice rather
8	// than failing.
9	//
10	// Asserts:
11	//   1. Missing Authorization → 401 UNAUTHORIZED                               [always]
12	//   2. Non-Bearer token → 401 UNAUTHORIZED                                    [always]
13	//   3. JWT signed with wrong secret → 401 UNAUTHORIZED                        [always]
14	//   4. Lister-role JWT → 403 FORBIDDEN                                        [jwtSecret]
15	//   5. Malformed JSON body → 400 INVALID_JSON                                 [jwtSecret]
16	//   6. Missing listing_id → 400 INVALID_REQUEST                               [jwtSecret]
17	//   7. Non-UUID listing_id → 400 INVALID_REQUEST                              [jwtSecret]
18	//   8. Non-string cover_note → 400 INVALID_REQUEST                            [jwtSecret]
19	//   9. Over-long cover_note → 400 INVALID_REQUEST                             [jwtSecret]
20	//  10. Unknown listing_id → 404 LISTING_NOT_FOUND                             [jwtSecret]
21	//  11. Ineligible listing (forced tiktok_follower_count=500, threshold 1000)
22	//      → 403 INELIGIBLE with failed_conditions containing tiktok
23	//        min_followers required=1000 actual=500                               [jwtSecret + serviceRole]
24	//  12. Happy path — seed creator applies to seed listing with a cover_note →
25	//      200 with { application_id, listing_version_id }                        [jwtSecret + serviceRole]
26	//  13. Second apply to the same listing by the same creator
27	//      → 409 ALREADY_APPLIED                                                  [jwtSecret + serviceRole]
28	//
29	// The happy-path test cleans up the inserted application row at the end
30	// (idempotency across re-runs). Test row pattern:
31	//   applications.listing_id      = SEED_LISTING_ID
32	//   applications.creator_id      = SEED_CREATOR_USER_ID
33	//   applications.cover_note LIKE 'US-041 smoke test%'
34	// All rows matching that cover_note pattern are deleted in the `finally`
35	// block so a failed mid-run doesn't poison subsequent runs.
36	
37	const supabaseUrl = process.env.SUPABASE_URL;
38	const anonKey = process.env.SUPABASE_ANON_KEY;
39	const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
40	const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
41	if (!supabaseUrl || !anonKey) {
42	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
43	  process.exit(1);
44	}
