  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  const token = bearerToken(req);
  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });

  let claims;
  try {
    claims = await verifyJwt(token);
  } catch {
    return jsonResponse(401, { error: "UNAUTHORIZED" });
  }
  if (claims.role !== "creator") {
    return jsonResponse(403, { error: "FORBIDDEN" });
  }

  let body: ApplyRequest;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const listingId =
    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
      ? body.listing_id
      : null;
  if (!listingId) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }

  let coverNote: string | null = null;
  if (body.cover_note !== undefined && body.cover_note !== null) {
    if (typeof body.cover_note !== "string") {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    const trimmed = body.cover_note.trim();
    if (trimmed.length > COVER_NOTE_MAX_LEN) {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    coverNote = trimmed.length > 0 ? trimmed : null;
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data: listing, error: listingError } = await supabase
    .from("listings")
    .select("id,status,current_version_id")
    .eq("id", listingId)
    .maybeSingle();

  if (listingError) {
    console.error("listings lookup failed", listingError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  // Draft and archived collapse to 404 to match get-listing-detail's
  // visibility rules — there's nothing to apply to and we don't want to
  // leak id existence.
  if (!listing || listing.status === "draft" || listing.status === "archived") {
    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
  }
  // Non-active (paused / closed) listings are a 409 per §5.5. They are
  // visible for detail view but not applyable.
  if (listing.status !== "active") {
    return jsonResponse(409, { error: "LISTING_NOT_ACTIVE" });
  }

  const versionId = listing.current_version_id as string | null;
  if (!versionId) {
    console.error("listing missing current_version_id", listing.id);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const [conditionsRes, profileRes] = await Promise.all([
    supabase
      .from("listing_conditions")
      .select("*")
      .eq("listing_version_id", versionId),
    supabase
      .from("creator_profiles")
      .select(
        "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
          "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
          "instagram_avg_views_last_10,instagram_media_count",
      )
      .eq("user_id", claims.sub)
      .maybeSingle(),
  ]);

  if (conditionsRes.error) {
    console.error("listing_conditions lookup failed", conditionsRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  if (profileRes.error) {
    console.error("creator_profiles lookup failed", profileRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
  const metrics: CreatorProfileRow = profileRes.data ?? EMPTY_CREATOR_METRICS;
  const failed = evaluatePreConditions(conditions, metrics);
  if (failed.length > 0) {
    return jsonResponse(403, {
      error: "INELIGIBLE",
      failed_conditions: failed,
    });
  }

  const { data: rpcData, error: rpcError } = await supabase.rpc(
    "apply_to_listing_rpc",
    {
      p_listing_id: listingId,
      p_creator_id: claims.sub,
      p_expected_version_id: versionId,
      p_cover_note: coverNote,
    },
  );

  if (rpcError) {
    console.error("apply_to_listing_rpc error", rpcError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const result = rpcData as
    | {
      application_id?: string;
      listing_version_id?: string;
      error?: string;
      current_version_id?: string;
    }
    | null;

  if (result?.error === "LISTING_NOT_FOUND") {
    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
  }
  if (result?.error === "LISTING_NOT_ACTIVE") {
    return jsonResponse(409, { error: "LISTING_NOT_ACTIVE" });
  }
  if (result?.error === "LISTING_VERSION_CHANGED") {
    return jsonResponse(409, {
      error: "LISTING_VERSION_CHANGED",
      current_version_id: result.current_version_id,
    });
  }
  if (result?.error === "ALREADY_APPLIED") {
    return jsonResponse(409, { error: "ALREADY_APPLIED" });
  }

  if (!result?.application_id || !result.listing_version_id) {
    console.error("apply_to_listing_rpc returned unexpected shape", result);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  return jsonResponse(200, {
    application_id: result.application_id,
    listing_version_id: result.listing_version_id,
  });
});
"},{"name":"_shared/jwt.ts","content":"// Custom JWT helper for Marketify edge functions.
//
// Contract: signJwt({ sub, role, session_id }, { ttlSeconds? }) -> compact JWT.
//           verifyJwt(token) -> parsed claims or throws.
// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
// Secret: MARKETIFY_JWT_SECRET env var — this is OUR signing key, deliberately
//         separate from Supabase's built-in JWT secret. Every `/auth/*` edge
//         function mints tokens here; RLS policies read `sub` and `role` via
//         `auth.jwt()`. `session_id` feeds the denylist lookup in §15c.
// Auth:   no inbound auth requirement — this module is a building block.

export type UserRole = "creator" | "lister";

export interface JwtClaims {
  sub: string;
  role: UserRole;
  session_id: string;
  iat: number;
  exp: number;
}

export interface SignInput {
  sub: string;
  role: UserRole;
  session_id: string;
}

export interface SignOptions {
  ttlSeconds?: number;
}

const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
const encoder = new TextEncoder();
const decoder = new TextDecoder();

function readSecret(): string {
  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
  return s;
}

function base64UrlEncode(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
}

function base64UrlDecode(input: string): Uint8Array {
  const rem = input.length % 4;
  const b64 = (rem === 0 ? input : input + "=".repeat(4 - rem))
    .replaceAll("-", "+")
    .replaceAll("_", "/");
  let raw: string;
  try {
    raw = atob(b64);
  } catch {
    throw new Error("Malformed JWT");
  }
  const out = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
  return out;
}

async function importKey(
  secret: string,
  usages: KeyUsage[],
): Promise<CryptoKey> {
  return await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    usages,
  );
}

export async function signJwt(
  input: SignInput,
  options: SignOptions = {},
): Promise<string> {
  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
  if (!Number.isFinite(ttl) || ttl <= 0) {
    throw new Error("ttlSeconds must be a positive finite number");
  }
  if (input.role !== "creator" && input.role !== "lister") {
    throw new Error("role must be 'creator' or 'lister'");
  }

  const now = Math.floor(Date.now() / 1000);
  const payload: JwtClaims = {
    sub: input.sub,
    role: input.role,
    session_id: input.session_id,
    iat: now,
    exp: now + ttl,
  };

  const headerB64 = base64UrlEncode(
    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
  );
  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
  const signingInput = `${headerB64}.${payloadB64}`;

  const key = await importKey(readSecret(), ["sign"]);
  const sig = await crypto.subtle.sign(
    "HMAC",
    key,
    encoder.encode(signingInput),
  );
  const sigB64 = base64UrlEncode(new Uint8Array(sig));

  return `${signingInput}.${sigB64}`;
}

export async function verifyJwt(token: string): Promise<JwtClaims> {
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("Malformed JWT");
  const [headerB64, payloadB64, sigB64] = parts;

  let header: { alg?: string };
  try {
    header = JSON.parse(decoder.decode(base64UrlDecode(headerB64)));
  } catch {
    throw new Error("Malformed JWT");
  }
  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");

  const key = await importKey(readSecret(), ["verify"]);
  const ok = await crypto.subtle.verify(
    "HMAC",
    key,
    base64UrlDecode(sigB64),
    encoder.encode(`${headerB64}.${payloadB64}`),
  );
  if (!ok) throw new Error("Bad signature");

  let payload: Partial<JwtClaims>;
  try {
    payload = JSON.parse(decoder.decode(base64UrlDecode(payloadB64)));
  } catch {
    throw new Error("Malformed JWT");
  }

  if (
    typeof payload.sub !== "string" || payload.sub.length === 0 ||
    (payload.role !== "creator" && payload.role !== "lister") ||
    typeof payload.session_id !== "string" ||
    payload.session_id.length === 0 ||
    typeof payload.iat !== "number" ||
    typeof payload.exp !== "number"
  ) {
    throw new Error("JWT missing required claims");
  }

  const now = Math.floor(Date.now() / 1000);
  if (payload.exp <= now) throw new Error("JWT expired");
  if (payload.iat > now + 60) throw new Error("JWT iat in the future");

  return payload as JwtClaims;
}
"},{"name":"_shared/cors.ts","content":"// Shared CORS headers for every Marketify edge function.
//
// Contract: exports `corsHeaders` (Record<string, string>) to splat into
//           every edge function's response and a pre-flight short-circuit.
// Auth:     n/a — the browser reads these before the request runs.
//
// `*` origin is safe here: edge functions authenticate via the
// Authorization: Bearer <marketify_jwt> header, not cookies, so there is no
// ambient-credential risk to guard against with a narrower origin allowlist.

export const corsHeaders: Record<string, string> = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
};
"},{"name":"_shared/eligibility.ts","content":"// Eligibility engine — shared between get-listing-detail and
// apply-to-listing (US-039 + US-041).
//
// Pre-conditions are evaluated against the creator's denormalized metrics
// from `creator_profiles`. Only pre-conditions gate apply-time eligibility
// per docs/tech-architecture.md §6.3. Post-conditions are returned by
// get-listing-detail for UI display and evaluated later on submissions.
//
// Fail-closed on missing metrics (§3d): when the creator hasn't been
// scraped yet (or a specific platform field is NULL), the pre-condition
// keyed on that field fails. Same rule extends to pre-condition rows with
// an unknown operator or unreadable metric — treat as failed rather than
// silently pass, so a future mis-migrated row can't flip a listing to
// eligible by accident.

export type Platform = "tiktok" | "instagram";
export type ConditionKind = "pre" | "post";

export interface ConditionRow {
  id: string;
  listing_version_id: string;
  kind: ConditionKind;
  metric: string;
  platform: Platform | null;
  operator: string;
  numeric_threshold: string | number | null;
  text_threshold: string | null;
  bool_threshold: boolean | null;
  created_at: string;
}

export interface CreatorProfileRow {
  tiktok_follower_count: number | null;
  tiktok_avg_views_last_10: number | null;
  tiktok_total_likes: number | null;
  tiktok_video_count: number | null;
  tiktok_is_verified: boolean | null;
  instagram_follower_count: number | null;
  instagram_avg_views_last_10: number | null;
  instagram_media_count: number | null;
}

export interface FailedCondition {
  metric: string;
  platform: Platform | null;
  required: number | boolean;
  actual: number | boolean | null;
}

export const EMPTY_CREATOR_METRICS: CreatorProfileRow = {
  tiktok_follower_count: null,
  tiktok_avg_views_last_10: null,
  tiktok_total_likes: null,
  tiktok_video_count: null,
  tiktok_is_verified: null,
  instagram_follower_count: null,
  instagram_avg_views_last_10: null,
  instagram_media_count: null,
};

// Evaluate a single pre-condition against the creator's denormalized
// metrics. Returns `null` on pass, or the failed-condition detail on fail.
// Missing data (null actual for a numeric threshold) fails closed per §3d.
export function evaluatePreCondition(
  condition: ConditionRow,
  metrics: CreatorProfileRow,
): FailedCondition | null {
  const { metric, platform, operator } = condition;
  if (operator === "gte") {
    const required = Number(condition.numeric_threshold);
    // Malformed numeric_threshold (NULL or non-numeric) fails closed per §3d —
    // schema CHECKs should prevent this today, but a future mis-migrated row
    // must not flip a condition to "always passes" just because it's unreadable.
    if (!Number.isFinite(required)) {
      return { metric, platform, required: 0, actual: null };
    }
    const actual = readNumericMetric(metrics, platform, metric);
    if (actual === null || actual < required) {
      return { metric, platform, required, actual };
    }
    return null;
  }
  if (operator === "bool") {
    const required = condition.bool_threshold === true;
    const actual = readBoolMetric(metrics, platform, metric);
    if (actual !== required) {
      return { metric, platform, required, actual };
    }
    return null;
  }
  // Unknown operator on a PRE row — fail-closed per §3d. `eq`/`contains`/`lte`
  // are reserved for post-conditions today (e.g. post_must_mention uses
  // 'contains'), so this branch should be unreachable; if a future migration
  // misplaces an operator, we'd rather block an apply than silently allow it.
  console.warn("pre-condition with unknown operator treated as failed", {
    condition_id: condition.id,
    operator,
    metric,
    platform,
  });
  const parsed = Number(condition.numeric_threshold);
  return {
    metric,
    platform,
    required: Number.isFinite(parsed) ? parsed : 0,
    actual: null,
  };
}

// Evaluate every pre-condition and return the (possibly empty) list of
// failures. Post-conditions are ignored.
export function evaluatePreConditions(
  conditions: ConditionRow[],
  metrics: CreatorProfileRow,
): FailedCondition[] {
  const failed: FailedCondition[] = [];
  for (const c of conditions) {
    if (c.kind !== "pre") continue;
    const miss = evaluatePreCondition(c, metrics);
    if (miss) failed.push(miss);
  }
  return failed;
}

function readNumericMetric(
  metrics: CreatorProfileRow,
  platform: Platform | null,
  metric: string,
): number | null {
  if (platform === "tiktok") {
    switch (metric) {
      case "min_followers":
        return metrics.tiktok_follower_count;
      case "min_avg_views_last_n":
        return metrics.tiktok_avg_views_last_10;
      case "min_total_likes":
        return metrics.tiktok_total_likes;
      case "min_videos_posted":
        return metrics.tiktok_video_count;
      default:
        return null;
    }
  }
  if (platform === "instagram") {
    switch (metric) {
      case "min_followers":
        return metrics.instagram_follower_count;
      case "min_avg_views_last_n":
        return metrics.instagram_avg_views_last_10;
      case "min_videos_posted":
        return metrics.instagram_media_count;
      default:
        return null;
    }
  }
  return null;
}

function readBoolMetric(
  metrics: CreatorProfileRow,
  platform: Platform | null,
  metric: string,
): boolean | null {
  if (platform === "tiktok" && metric === "verified_only") {
    return metrics.tiktok_is_verified;
  }
  return null;
}
"}]}

files.content:
// Edge function: submit-video (US-045)
//
// Contract:
//   POST { application_id: string,
//          video_url: string,
//          post_condition_affirmations: { [condition_id: string]: boolean } }
//     → 200 { submission_id: string, platform: 'tiktok'|'instagram' }
//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
//     → 401 { error: 'UNAUTHORIZED' }
//     → 403 { error: 'FORBIDDEN' }                       // non-creator role
//     → 403 { error: 'APPLICATION_NOT_APPROVED' }
//     → 404 { error: 'APPLICATION_NOT_FOUND' }
//     → 409 { error: 'SUBMISSION_EXISTS' }
//     → 422 { error: 'INVALID_VIDEO_URL' }
//     → 422 { error: 'INCOMPLETE_AFFIRMATIONS',
//             missing_condition_ids: string[] }
//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
//
// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Deployed with
//       verify_jwt=false at the gateway because the gateway only knows
//       about Supabase's own JWT secret — the handler enforces auth.
//
// Request shape — the US-045 story AC specifies `{ application_id,
// video_url, post_condition_affirmations }`. The tech-architecture spec
// §5.7 names a future-compatible `{ videos: [...] }` array shape; per
// the Ralph convention when story AC and spec disagree at the field
// level the story AC wins. The DB layer models multi-video via
// `submission_videos.sort_order` so expanding to an array later is a
// non-breaking change to this endpoint.
//
// URL validation (docs/tech-architecture.md §3h):
//   - TikTok canonical + shortlinks accepted; canonical gives us the
//     numeric `external_id`.
//   - TikTok oEmbed endpoint is called to prove the URL points at a
//     real, currently-resolvable post. A 404 from TikTok → 422
//     INVALID_VIDEO_URL. Network/5xx failures from TikTok → 500.
//   - Instagram URLs are validated by regex-shape only because IG
//     oEmbed requires an app-level Meta token that we do not currently
//     have provisioned. See `_shared/oembed.ts` header.
//
// Affirmation gate — the spec treats POST conditions (e.g.
// "must_mention", "family_friendly") as creator attestations at
// submit-time rather than machine-checkable facts. Every `post`-kind
// condition on the application's pinned listing_version_id must appear
// in `post_condition_affirmations` with a literal `true` value. Missing
// or `false` entries → 422 INCOMPLETE_AFFIRMATIONS with the offending
// ids so the client can re-surface them.
//
// Concurrency — the RPC acquires a row lock on the application
// (FOR UPDATE) so a duplicate submit interleaving with this one is
// serialised and the second request receives SUBMISSION_EXISTS. The
// partial unique index `submissions_open_uniq` is the DB backstop.

import { createClient } from "npm:@supabase/supabase-js@2";
import { verifyJwt } from "../_shared/jwt.ts";
import { corsHeaders } from "../_shared/cors.ts";
import {
  classifyVideoUrl,
  fetchTikTokOembed,
  type OembedResult,
} from "../_shared/oembed.ts";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

// Guard against a malicious client pasting a megabyte of URL. TikTok /
// Instagram share URLs cap well under 300 chars in the wild; 2048 is
// the de facto browser URL ceiling.
const VIDEO_URL_MAX_LEN = 2048;

interface SubmitVideoRequest {
  application_id?: unknown;
  video_url?: unknown;
  post_condition_affirmations?: unknown;
}

function jsonResponse(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function bearerToken(req: Request): string | null {
  const raw = req.headers.get("Authorization") ??
    req.headers.get("authorization");
  if (!raw) return null;
  const m = raw.match(/^Bearer\s+(.+)$/i);
  return m ? m[1].trim() : null;
}

function parseAffirmations(
  raw: unknown,
): Record<string, boolean> | null {
  if (raw === null || typeof raw !== "object" || Array.isArray(raw)) {
    return null;
  }
  const out: Record<string, boolean> = {};
  for (const [key, value] of Object.entries(raw as Record<string, unknown>)) {
    if (typeof value !== "boolean") return null;
    out[key] = value;
  }
  return out;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  const token = bearerToken(req);
  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });

  let claims;
  try {
    claims = await verifyJwt(token);
  } catch {
    return jsonResponse(401, { error: "UNAUTHORIZED" });
  }
  if (claims.role !== "creator") {
    return jsonResponse(403, { error: "FORBIDDEN" });
  }

  let body: SubmitVideoRequest;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const applicationId =
    typeof body.application_id === "string" && UUID_RE.test(body.application_id)
      ? body.application_id
      : null;
  if (!applicationId) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }

  if (
    typeof body.video_url !== "string" ||
    body.video_url.trim().length === 0 ||
    body.video_url.length > VIDEO_URL_MAX_LEN
  ) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }
  const videoUrl = body.video_url.trim();

  const affirmations = parseAffirmations(body.post_condition_affirmations);
  if (affirmations === null) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }

  const classification = classifyVideoUrl(videoUrl);
  if (!classification) {
    return jsonResponse(422, { error: "INVALID_VIDEO_URL" });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data: application, error: appError } = await supabase
    .from("applications")
    .select("id,creator_id,status,listing_version_id")
    .eq("id", applicationId)
    .maybeSingle();

  if (appError) {
    console.error("applications lookup failed", appError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  if (!application || application.creator_id !== claims.sub) {
    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
  }
  if (application.status !== "approved") {
    return jsonResponse(403, { error: "APPLICATION_NOT_APPROVED" });
  }

  const { data: postConditions, error: condError } = await supabase
    .from("listing_conditions")
    .select("id")
    .eq("listing_version_id", application.listing_version_id)
    .eq("kind", "post");

  if (condError) {
    console.error("listing_conditions lookup failed", condError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const missing: string[] = [];
  for (const row of postConditions ?? []) {
    if (affirmations[row.id] !== true) missing.push(row.id);
  }
  if (missing.length > 0) {
    return jsonResponse(422, {
      error: "INCOMPLETE_AFFIRMATIONS",
      missing_condition_ids: missing,
    });
  }

  // oEmbed lives after the cheap checks — a TikTok network call on a
  // request that would 404/403/422 anyway is pure waste and exposes
  // rate-limit surface to unauthenticated noise.
  let oembed: OembedResult | null = null;
  if (classification.platform === "tiktok") {
    try {
      oembed = await fetchTikTokOembed(videoUrl);
    } catch (err) {
      console.error("TikTok oEmbed fetch error", err);
      return jsonResponse(500, { error: "DB_ERROR" });
    }
    if (!oembed) {
      return jsonResponse(422, { error: "INVALID_VIDEO_URL" });
    }
  }

  const { data: rpcData, error: rpcError } = await supabase.rpc(
    "submit_video_rpc",
    {
      p_application_id: applicationId,
      p_creator_id: claims.sub,
      p_video_url: videoUrl,
      p_platform: classification.platform,
      p_external_id: classification.externalId,
      p_oembed: oembed ? oembed.raw : null,
    },
  );

  if (rpcError) {
    console.error("submit_video_rpc error", rpcError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const result = rpcData as
    | { submission_id?: string; error?: string }
    | null;

  if (result?.error === "APPLICATION_NOT_FOUND") {
    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
  }
  if (result?.error === "APPLICATION_NOT_APPROVED") {
    return jsonResponse(403, { error: "APPLICATION_NOT_APPROVED" });
  }
  if (result?.error === "SUBMISSION_EXISTS") {
    return jsonResponse(409, { error: "SUBMISSION_EXISTS" });
  }

  if (!result?.submission_id) {
    console.error("submit_video_rpc returned unexpected shape", result);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  return jsonResponse(200, {
    submission_id: result.submission_id,
    platform: classification.platform,
  });
});

// Custom JWT helper for Marketify edge functions.
//
// Contract: signJwt({ sub, role, session_id }, { ttlSeconds? }) -> compact JWT.
//           verifyJwt(token) -> parsed claims or throws.
// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
// Secret: MARKETIFY_JWT_SECRET env var — this is OUR signing key, deliberately
//         separate from Supabase's built-in JWT secret. Every `/auth/*` edge
//         function mints tokens here; RLS policies read `sub` and `role` via
//         `auth.jwt()`. `session_id` feeds the denylist lookup in §15c.
// Auth:   no inbound auth requirement — this module is a building block.

export type UserRole = "creator" | "lister";

export interface JwtClaims {
  sub: string;
  role: UserRole;
  session_id: string;
  iat: number;
  exp: number;
}

export interface SignInput {
  sub: string;
  role: UserRole;
  session_id: string;
}

export interface SignOptions {
  ttlSeconds?: number;
}

const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
const encoder = new TextEncoder();
const decoder = new TextDecoder();

function readSecret(): string {
  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
  return s;
}

function base64UrlEncode(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
}

function base64UrlDecode(input: string): Uint8Array {
  const rem = input.length % 4;
  const b64 = (rem === 0 ? input : input + "=".repeat(4 - rem))
    .replaceAll("-", "+")
    .replaceAll("_", "/");
  let raw: string;
  try {
    raw = atob(b64);
  } catch {
    throw new Error("Malformed JWT");
  }
  const out = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
  return out;
}

async function importKey(
  secret: string,
  usages: KeyUsage[],
): Promise<CryptoKey> {
  return await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    usages,
  );
}

export async function signJwt(
  input: SignInput,
  options: SignOptions = {},
): Promise<string> {
  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
  if (!Number.isFinite(ttl) || ttl <= 0) {
    throw new Error("ttlSeconds must be a positive finite number");
  }
  if (input.role !== "creator" && input.role !== "lister") {
    throw new Error("role must be 'creator' or 'lister'");
  }

  const now = Math.floor(Date.now() / 1000);
  const payload: JwtClaims = {
    sub: input.sub,
    role: input.role,
    session_id: input.session_id,
    iat: now,
    exp: now + ttl,
  };

  const headerB64 = base64UrlEncode(
    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
  );
  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
  const signingInput = `${headerB64}.${payloadB64}`;

  const key = await importKey(readSecret(), ["sign"]);
  const sig = await crypto.subtle.sign(
    "HMAC",
    key,
    encoder.encode(signingInput),
  );
  const sigB64 = base64UrlEncode(new Uint8Array(sig));

  return `${signingInput}.${sigB64}`;
}

export async function verifyJwt(token: string): Promise<JwtClaims> {
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("Malformed JWT");
  const [headerB64, payloadB64, sigB64] = parts;

  let header: { alg?: string };
  try {
    header = JSON.parse(decoder.decode(base64UrlDecode(headerB64)));
  } catch {
    throw new Error("Malformed JWT");
  }
  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");

  const key = await importKey(readSecret(), ["verify"]);
  const ok = await crypto.subtle.verify(
    "HMAC",
    key,
    base64UrlDecode(sigB64),
    encoder.encode(`${headerB64}.${payloadB64}`),
  );
  if (!ok) throw new Error("Bad signature");

  let payload: Partial<JwtClaims>;
  try {
    payload = JSON.parse(decoder.decode(base64UrlDecode(payloadB64)));
  } catch {
    throw new Error("Malformed JWT");
  }

  if (
    typeof payload.sub !== "string" || payload.sub.length === 0 ||
    (payload.role !== "creator" && payload.role !== "lister") ||
    typeof payload.session_id !== "string" ||
    payload.session_id.length === 0 ||
    typeof payload.iat !== "number" ||
    typeof payload.exp !== "number"
  ) {
    throw new Error("JWT missing required claims");
  }

  const now = Math.floor(Date.now() / 1000);
  if (payload.exp <= now) throw new Error("JWT expired");
  if (payload.iat > now + 60) throw new Error("JWT iat in the future");

  return payload as JwtClaims;
}

// Shared CORS headers for every Marketify edge function.
//
// Contract: exports `corsHeaders` (Record<string, string>) to splat into
//           every edge function's response and a pre-flight short-circuit.
// Auth:     n/a — the browser reads these before the request runs.
//
// `*` origin is safe here: edge functions authenticate via the
// Authorization: Bearer <marketify_jwt> header, not cookies, so there is no
// ambient-credential risk to guard against with a narrower origin allowlist.

export const corsHeaders: Record<string, string> = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
};

// URL classification + oEmbed fetch for TikTok / Instagram post URLs.
//
// Consumers: submit-video (US-045). Extend here before adding platforms.
//
// Platform detection is based on URL host + path shape — we accept the
// common formats a creator is likely to paste:
//   TikTok:    https://www.tiktok.com/@handle/video/1234567890
//              https://vm.tiktok.com/XXXXXXX/      (share redirect)
//              https://vt.tiktok.com/XXXXXXX/      (share redirect)
//              https://www.tiktok.com/t/XXXXXXX/   (share redirect)
//   Instagram: https://www.instagram.com/p/<code>/
//              https://www.instagram.com/reel/<code>/
//              https://www.instagram.com/tv/<code>/
//
// external_id extraction is best-effort. For canonical TikTok URLs the
// trailing numeric video id is the external_id; for shortlinks we leave
// external_id null and let the oEmbed response (if available) provide it
// via provider-specific fields (currently unused). The
// `submission_reuse_view` in public skips rows with external_id IS NULL,
// so shortlink-only rows simply don't participate in reuse counting until
// the lister paste-flow hands us a canonical URL.
//
// oEmbed endpoints (docs/tech-architecture.md §3h):
//   TikTok:    GET https://www.tiktok.com/oembed?url=<share_url>      (no auth)
//   Instagram: GET https://graph.facebook.com/v<ver>/instagram_oembed (app-token)
//
// Instagram oEmbed requires an app-level Meta token. We do NOT have one
// configured, so IG validation here is regex-shape only; the spec §3h
// notes this requirement. Expand `fetchOembed` once the token is wired.

export type OembedPlatform = "tiktok" | "instagram";

export interface UrlClassification {
  platform: OembedPlatform;
  externalId: string | null;
}

export interface OembedResult {
  thumbnailUrl: string | null;
  authorHandle: string | null;
  raw: Record<string, unknown>;
}

const TIKTOK_CANONICAL_RE =
  /^https:\/\/(?:www\.)?tiktok\.com\/@[A-Za-z0-9._-]+\/video\/(\d+)/i;
const TIKTOK_SHORTLINK_RE =
  /^https:\/\/(?:vm|vt)\.tiktok\.com\/[A-Za-z0-9]+\/?/i;
const TIKTOK_TLINK_RE =
  /^https:\/\/(?:www\.)?tiktok\.com\/t\/[A-Za-z0-9]+\/?/i;

const INSTAGRAM_RE =
  /^https:\/\/(?:www\.)?instagram\.com\/(?:p|reel|tv)\/([A-Za-z0-9_-]+)\/?/i;

export function classifyVideoUrl(url: string): UrlClassification | null {
  if (typeof url !== "string") return null;
  const trimmed = url.trim();
  if (trimmed.length === 0) return null;

  const canon = trimmed.match(TIKTOK_CANONICAL_RE);
  if (canon) {
    return { platform: "tiktok", externalId: canon[1] };
  }
  if (TIKTOK_SHORTLINK_RE.test(trimmed) || TIKTOK_TLINK_RE.test(trimmed)) {
    return { platform: "tiktok", externalId: null };
  }
  const ig = trimmed.match(INSTAGRAM_RE);
  if (ig) {
    return { platform: "instagram", externalId: ig[1] };
  }
  return null;
}

export async function fetchTikTokOembed(
  url: string,
): Promise<OembedResult | null> {
  const endpoint = `https://www.tiktok.com/oembed?url=${encodeURIComponent(url)}`;
  let response: Response;
  try {
    response = await fetch(endpoint, {
      headers: { "User-Agent": "marketify-submit-video/1.0" },
    });
  } catch (_err) {
    // Network failures are treated as "URL could not be validated" at the
    // caller's discretion. Throw fixed-string errors rather than ${err}
    // to avoid leaking internal paths if fetch implementations ever grow
    // diagnostic info.
    throw new Error("TikTok oEmbed fetch failed");
  }
  if (response.status === 404 || response.status === 400) {
    return null;
  }
  if (!response.ok) {
    throw new Error(`TikTok oEmbed HTTP ${response.status}`);
  }
  let data: Record<string, unknown>;
  try {
    data = await response.json();
  } catch {
    throw new Error("TikTok oEmbed returned non-JSON");
  }
  const thumbnailUrl = typeof data.thumbnail_url === "string"
    ? data.thumbnail_url
    : null;
  const authorHandle = extractTikTokAuthorHandle(data);
  return { thumbnailUrl, authorHandle, raw: data };
}

function extractTikTokAuthorHandle(
  data: Record<string, unknown>,
): string | null {
  // TikTok's oEmbed returns `author_unique_id` (canonical handle) and
  // `author_name` (display name). Prefer the unique id; strip any leading
  // @ because our social_links.handle is stored without it.
  const candidates = [data.author_unique_id, data.author_name];
  for (const raw of candidates) {
    if (typeof raw === "string") {
      const h = raw.trim().replace(/^@+/, "");
      if (h.length > 0) return h;
    }
  }
  return null;
}

